solution_code:
#include <iostream>
#include <string>

struct Student
{
    std::string name;
    int totalScore;
    char grade{ 'F' };
};

int computeAverage(const Student& s)
{
    return s.totalScore / 3;
}

void assignGrade(Student& s)
{
    int avg{ computeAverage(s) };
    if (avg >= 90)
        s.grade = 'A';
    else if (avg >= 80)
        s.grade = 'B';
    else if (avg >= 70)
        s.grade = 'C';
    else if (avg >= 60)
        s.grade = 'D';
    else
        s.grade = 'F';
}

int main()
{
    std::string name;
    int s1{}, s2{}, s3{};
    std::cin >> name >> s1 >> s2 >> s3;

    Student student{ name, s1 + s2 + s3 };
    assignGrade(student);

    std::cout << student.name << ": avg " << computeAverage(student) << '\n';
    std::cout << student.name << ": grade " << student.grade << '\n';

    return 0;
}
